using ContosoUniversity.Models;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        private IQueryable<int> GetTestData(int count)
        {
            return Enumerable.Range(1, count).AsQueryable();
        }

        [Fact]
        public void Create_FirstPage_ReturnsCorrectItems()
        {
            var source = GetTestData(25);

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(10, result.Count);
            Assert.Equal(1, result[0]);
            Assert.Equal(10, result[9]);
        }

        [Fact]
        public void Create_SecondPage_ReturnsCorrectItems()
        {
            var source = GetTestData(25);

            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.Equal(10, result.Count);
            Assert.Equal(11, result[0]);
            Assert.Equal(20, result[9]);
        }

        [Fact]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            var source = GetTestData(25);

            var result = PaginatedList<int>.Create(source, 3, 10);

            Assert.Equal(5, result.Count);
            Assert.Equal(21, result[0]);
            Assert.Equal(25, result[4]);
        }

        [Fact]
        public void TotalPages_CalculatedCorrectly()
        {
            var source = GetTestData(25);

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(3, result.TotalPages);
        }

        [Fact]
        public void TotalPages_ExactDivision_NoExtraPage()
        {
            var source = GetTestData(20);

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(2, result.TotalPages);
        }

        [Fact]
        public void TotalPages_SingleItem_OnePage()
        {
            var source = GetTestData(1);

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(1, result.TotalPages);
        }

        [Fact]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            var source = GetTestData(25);

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.False(result.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_SecondPage_ReturnsTrue()
        {
            var source = GetTestData(25);

            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.True(result.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_FirstPage_ReturnsTrue()
        {
            var source = GetTestData(25);

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.True(result.HasNextPage);
        }

        [Fact]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
            var source = GetTestData(25);

            var result = PaginatedList<int>.Create(source, 3, 10);

            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void PageIndex_IsSetCorrectly()
        {
            var source = GetTestData(25);

            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.Equal(2, result.PageIndex);
        }

        [Fact]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var source = Enumerable.Empty<int>().AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Empty(result);
            Assert.Equal(0, result.TotalPages);
        }

        [Fact]
        public void Create_PageSizeOne_CorrectTotalPages()
        {
            var source = GetTestData(5);

            var result = PaginatedList<int>.Create(source, 1, 1);

            Assert.Single(result);
            Assert.Equal(5, result.TotalPages);
        }

        [Fact]
        public void Constructor_SetsProperties()
        {
            var items = new List<int> { 1, 2, 3 };

            var paginatedList = new PaginatedList<int>(items, 30, 2, 10);

            Assert.Equal(2, paginatedList.PageIndex);
            Assert.Equal(3, paginatedList.TotalPages);
            Assert.Equal(3, paginatedList.Count);
        }

        [Fact]
        public void HasPreviousPage_PageOne_False()
        {
            var items = new List<int> { 1 };
            var list = new PaginatedList<int>(items, 10, 1, 5);
            Assert.False(list.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_LastPage_False()
        {
            var items = new List<int> { 1 };
            var list = new PaginatedList<int>(items, 10, 2, 5);
            Assert.False(list.HasNextPage);
        }
    }
}

