+using ContosoUniversity.Services;
+using ContosoUniversity.Models;
+using Xunit;
+
+namespace ContosoUniversity.Tests.Services
+{
+    public class NotificationServiceTests : IDisposable
+    {
+        private readonly NotificationService _service;
+
+        public NotificationServiceTests()
+        {
+            _service = new NotificationService();
+            // Drain the static queue to avoid cross-test contamination
+            while (_service.ReceiveNotification() != null) { }
+        }
+
+        public void Dispose()
+        {
+            // Drain after test too
+            while (_service.ReceiveNotification() != null) { }
+            _service.Dispose();
+        }
+
+        [Fact]
+        public void SendNotification_WithDisplayName_EnqueuesNotification()
+        {
+            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");
+
+            var notification = _service.ReceiveNotification();
+
+            Assert.NotNull(notification);
+            Assert.Equal("Student", notification.EntityType);
+            Assert.Equal("1", notification.EntityId);
+            Assert.Equal("CREATE", notification.Operation);
+            Assert.Contains("Student 'John Doe'", notification.Message);
+            Assert.Contains("created", notification.Message);
+            Assert.Equal("Admin", notification.CreatedBy);
+            Assert.False(notification.IsRead);
+        }
+
+        [Fact]
+        public void SendNotification_WithoutDisplayName_UsesEntityId()
+        {
+            _service.SendNotification("Course", "101", EntityOperation.UPDATE, "System");
+
+            var notification = _service.ReceiveNotification();
+
+            Assert.NotNull(notification);
+            Assert.Contains("Course (ID: 101)", notification.Message);
+            Assert.Contains("updated", notification.Message);
+        }
+
+        [Fact]
+        public void SendNotification_DeleteOperation_GeneratesDeleteMessage()
+        {
+            _service.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE, "Admin");
+
+            var notification = _service.ReceiveNotification();
+
+            Assert.NotNull(notification);
+            Assert.Equal("DELETE", notification.Operation);
+            Assert.Contains("deleted", notification.Message);
+        }
+
+        [Fact]
+        public void SendNotification_NullUserName_DefaultsToSystem()
+        {
+            _service.SendNotification("Student", "1", EntityOperation.CREATE, null);
+
+            var notification = _service.ReceiveNotification();
+
+            Assert.NotNull(notification);
+            Assert.Equal("System", notification.CreatedBy);
+        }
+
+        [Fact]
+        public void SendNotification_SetsCreatedAtToNow()
+        {
+            var before = DateTime.Now.AddSeconds(-1);
+            _service.SendNotification("Student", "1", EntityOperation.CREATE);
+            var after = DateTime.Now.AddSeconds(1);
+
+            var notification = _service.ReceiveNotification();
+
+            Assert.NotNull(notification);
+            Assert.InRange(notification.CreatedAt, before, after);
+        }
+
+        [Fact]
+        public void ReceiveNotification_EmptyQueue_ReturnsNull()
+        {
+            var notification = _service.ReceiveNotification();
+            Assert.Null(notification);
+        }
+
+        [Fact]
+        public void ReceiveNotification_MultipleSends_ReturnsFIFO()
+        {
+            _service.SendNotification("Student", "1", EntityOperation.CREATE);
+            _service.SendNotification("Course", "101", EntityOperation.UPDATE);
+            _service.SendNotification("Department", "5", EntityOperation.DELETE);
+
+            var first = _service.ReceiveNotification();
+            var second = _service.ReceiveNotification();
+            var third = _service.ReceiveNotification();
+
+            Assert.Equal("Student", first.EntityType);
+            Assert.Equal("Course", second.EntityType);
+            Assert.Equal("Department", third.EntityType);
+        }
+
+        [Fact]
+        public void MarkAsRead_DoesNotThrow()
+        {
+            // MarkAsRead is a no-op in the in-memory implementation
+            var exception = Record.Exception(() => _service.MarkAsRead(1));
+            Assert.Null(exception);
+        }
+
+        [Fact]
+        public void SendNotification_ExceedsMaxQueue_OldestItemsRemoved()
+        {
+            // Send more than 500 notifications
+            for (int i = 0; i < 510; i++)
+            {
+                _service.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
+            }
+
+            // Drain all and count
+            int count = 0;
+            while (_service.ReceiveNotification() != null)
+            {
+                count++;
+            }
+
+            // Should be capped at approximately 500 (best-effort)
+            Assert.True(count <= 500);
+        }
+
+        [Fact]
+        public void SendNotification_TwoArgOverload_Works()
+        {
+            _service.SendNotification("Instructor", "42", EntityOperation.CREATE);
+
+            var notification = _service.ReceiveNotification();
+
+            Assert.NotNull(notification);
+            Assert.Equal("Instructor", notification.EntityType);
+            Assert.Equal("42", notification.EntityId);
+        }
+
+        [Fact]
+        public void Dispose_DoesNotThrow()
+        {
+            var service = new NotificationService();
+            var exception = Record.Exception(() => service.Dispose());
+            Assert.Null(exception);
+        }
+
+        [Theory]
+        [InlineData(EntityOperation.CREATE, "created")]
+        [InlineData(EntityOperation.UPDATE, "updated")]
+        [InlineData(EntityOperation.DELETE, "deleted")]
+        public void SendNotification_AllOperations_GenerateCorrectMessage(EntityOperation operation, string expectedVerb)
+        {
+            _service.SendNotification("Test", "1", "TestEntity", operation, "User");
+
+            var notification = _service.ReceiveNotification();
+
+            Assert.NotNull(notification);
+            Assert.Contains(expectedVerb, notification.Message);
+        }
+    }
+}
