using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class HomeControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly HomeController _controller;

        public HomeControllerTests()
        {
            _context = TestDbContextFactory.Create();
            _controller = new HomeController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Contact_ReturnsViewResult()
        {
            var result = _controller.Contact();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Error_ReturnsViewResult()
        {
            var result = _controller.Error();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Unauthorized_ReturnsViewResult()
        {
            var result = _controller.Unauthorized();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void About_NoStudents_ReturnsEmptyList()
        {
            var result = _controller.About() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<List<ContosoUniversity.Models.SchoolViewModels.EnrollmentDateGroup>>(result.Model);
            Assert.Empty(model);
        }

        [Fact]
        public void About_WithStudents_ReturnsGroupedData()
        {
            var date1 = new DateTime(2023, 9, 1);
            var date2 = new DateTime(2023, 1, 15);

            _context.Students.AddRange(
                new Student { LastName = "A", FirstMidName = "B", EnrollmentDate = date1 },
                new Student { LastName = "C", FirstMidName = "D", EnrollmentDate = date1 },
                new Student { LastName = "E", FirstMidName = "F", EnrollmentDate = date2 }
            );
            _context.SaveChanges();

            var result = _controller.About() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<List<ContosoUniversity.Models.SchoolViewModels.EnrollmentDateGroup>>(result.Model);
            Assert.Equal(2, model.Count);

            var group1 = model.First(g => g.EnrollmentDate == date1);
            Assert.Equal(2, group1.StudentCount);

            var group2 = model.First(g => g.EnrollmentDate == date2);
            Assert.Equal(1, group2.StudentCount);
        }

        [Fact]
        public void About_SingleStudent_ReturnsSingleGroup()
        {
