using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ModelBinding;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestDbContextFactory.Create();
            _controller = new InstructorsController(_context);
            // Set up controller context for TryUpdateModelAsync
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private Instructor CreateTestInstructor(string lastName = "Kapoor", string firstName = "Raj", DateTime? hireDate = null)
        {
            var instructor = new Instructor
            {
                LastName = lastName,
                FirstMidName = firstName,
                HireDate = hireDate ?? new DateTime(2010, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();
            return instructor;
        }

        private Course CreateTestCourse(int id, string title = "Test Course")
        {
            var dept = _context.Departments.FirstOrDefault();
            if (dept == null)
            {
                dept = new Department
                {
                    Name = "Test Dept",
                    Budget = 50000m,
                    StartDate = DateTime.Now
                };
                _context.Departments.Add(dept);
                _context.SaveChanges();
            }

            var course = new Course
            {
                CourseID = id,
                Title = title,
                Credits = 3,
                DepartmentID = dept.DepartmentID,
                CourseAssignments = new List<CourseAssignment>(),
                Enrollments = new List<Enrollment>()
            };
            _context.Courses.Add(course);
            _context.SaveChanges();
            return course;
        }

        #region Index Tests

        [Fact]
        public void Index_NoParams_ReturnsViewWithInstructors()
        {
            CreateTestInstructor();
            CreateTestInstructor("Smith", "Jane");

            var result = _controller.Index(null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.Equal(2, model.Instructors.Count());
        }

        [Fact]
        public void Index_WithInstructorId_ShowsCourses()
        {
            var instructor = CreateTestInstructor();
            var course = CreateTestCourse(100, "Math 101");

            var ca = new CourseAssignment { InstructorID = instructor.ID, CourseID = course.CourseID };
            _context.CourseAssignments.Add(ca);
            _context.SaveChanges();

            // Reload instructor with navigation properties
            var result = _controller.Index(instructor.ID, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.NotNull(model.Courses);
            Assert.Single(model.Courses);
        }

        [Fact]
        public void Index_NoInstructors_ReturnsEmptyList()
        {
            var result = _controller.Index(null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.Empty(model.Instructors);
        }

        #endregion

        #region Details Tests

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_NotFound_ReturnsNotFound()
        {
            var result = _controller.Details(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
            var instructor = CreateTestInstructor();

            var result = _controller.Details(instructor.ID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Kapoor", model.LastName);
        }

        #endregion

        #region Create Tests

        [Fact]
        public void Create_GET_ReturnsViewWithInstructor()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.NotNull(model.CourseAssignments);
        }

        [Fact]
