            var instructor = CreateTestInstructor();

            var result = await _controller.Edit(instructor.ID, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.Equal(instructor.ID, model.ID);
        }

